const body = $json.body ?? $json;
const factors = Array.isArray(body.explanatory_factors) ? body.explanatory_factors : [];
const model = 'openai/gpt-oss-20b';
const prompt = [
  'Contexte de la transaction :',
  `- prediction_id: ${body.prediction_id}`,
  `- email: ${body.customer_email}`,
  `- montant: ${body.amount} EUR`,
  `- prediction: ${body.predicted_label}`,
  `- fraud_probability: ${body.fraud_probability}`,
  `- facteurs: ${JSON.stringify(factors)}`,
  '',
  'Redige le sujet d email et un message client professionnel en francais.',
  'N inclus jamais d URL brute, de lien complet ou de jeton technique dans le texte.',
  'Le message doit rester court, rassurant, prudent et comprehensible par un client bancaire.',
  'Retourne strictement un JSON avec: email_subject, customer_message, recommended_action.'
].join('\n');
return [{
  json: {
    prediction_id: body.prediction_id,
    brand_name: body.brand_name,
    brand_logo_data_uri: body.brand_logo_data_uri,
    customer_email: body.customer_email,
    amount: body.amount,
    prediction: body.prediction,
    predicted_label: body.predicted_label,
    fraud_probability: body.fraud_probability,
    explanatory_factors: factors,
    confirm_url: body.confirm_url,
    reject_url: body.reject_url,
    email_subject: body.email_subject,
    customer_message_preview: body.customer_message_preview,
    recommended_action: body.recommended_action,
    analysis_timestamp: body.analysis_timestamp,
    analysis_context: body.analysis_context,
    groq_request: {
      model,
      temperature: 0.2,
      messages: [
        {
          role: 'system',
          content: 'Tu es l agent IA de FraudGuard AI. Tu n inventes pas de nouvelle decision de fraude. Tu expliques seulement la decision du modele ML et tu rediges un email prudent, clair et court.'
        },
        {
          role: 'user',
          content: prompt
        }
      ],
      response_format: {
        type: 'json_object'
      }
    }
  }
}];

const source = $items('Prepare Context', 0, 0)[0].json;
const raw = $json.choices?.[0]?.message?.content ?? '{}';
const sanitizeMessage = (value) => String(value ?? '').replace(/https?:\/\/\S+/g, '').replace(/\n{3,}/g, '\n\n').trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    email_subject: source.email_subject,
    customer_message: source.customer_message_preview,
    recommended_action: source.recommended_action,
  };
}
parsed = {
  email_subject: parsed.email_subject || source.email_subject,
  customer_message: sanitizeMessage(parsed.customer_message || source.customer_message_preview),
  recommended_action: parsed.recommended_action || source.recommended_action,
};
return [{ json: { ...source, llm_output: parsed } }];
